class Solution {
public:
    int smallestValue(int n) {
        int min_val = n;
        int current = n;
        while (true) {
            int sum = sum_prime_factors(current);
            if (sum < current) {
                min_val = std::min(min_val, sum);
                current = sum;
            } else {
                break;
            }
        }
        return min_val;
    }

private:
    int sum_prime_factors(int x) {
        int sum = 0;
        int i = 2;
        while (i * i <= x) {
            while (x % i == 0) {
                sum += i;
                x /= i;
            }
            i++;
        }
        if (x > 1) {
            sum += x;
        }
        return sum;
    }
};

